325→                  'F',
326→                ]}
327→              />
328→            ),
329→            onClick: handleShowInFinder,
330→          },
331→          createCopyAction(
332→            {
333→              content: selectedEntry?.path ?? '',
334→              title: 'Copy Path',
335→              shortcut: (
336→                <Kbd
