341→                />
342→              ),
343→              hudTitle: 'Path Copied',
344→            },
345→            showHUD,
346→          ),
347→        ],
348→      },
349→      {
350→        title: 'Danger Zone',
351→        actions: [
352→          {
353→            label: 'Move to Trash',
354→            shortcut: (
355→              <Kbd
356→                keys={[
357→                  '⌘',
358→                  '⌫',
359→                ]}
360→              />
361→            ),
362→            onClick: handleDelete,
363→          },
364→        ],
365→      },
366→    ],
367→    [
368→      selectedEntry?.path,
369→      handleOpen,
370→      handleShowInFinder,
371→      handleDelete,
372→      showHUD,
373→    ],
374→  );
375→
376→  const activeDescendantId =
377→    totalItemCount > 0 ? `list-item-${selectedIndex}` : undefined;
378→
379→  function renderFileItem(entry: FileEntry, idx: number): ReactNode {
380→    const sizeText = formatFileSize(entry.size);
381→    return (
382→      <ListItem
383→        key={entry.id}
384→        index={idx}
385→        icon={getFileIcon(entry.fileType)}
386→        title={entry.name}
387→        subtitle={entry.path}
388→        accessories={[
389→          {
390→            tag: {
391→              text: FILE_TYPE_LABELS[entry.fileType],
392→              color:
393→                entry.fileType === 'folder'
394→                  ? 'blue'
395→                  : entry.fileType === 'code'
396→                    ? 'purple'
397→                    : entry.fileType === 'image'
398→                      ? 'green'
399→                      : undefined,
400→            },
401→          },
402→          { text: sizeText },
403→          {
404→            text: formatRelativeDate(entry.modifiedAt, now),
405→            tooltip: entry.modifiedAt.toLocaleString(),
406→          },
407→        ]}
408→        query={query || undefined}
409→      />
410→    );
411→  }
412→
413→  return (
414→    <>
415→      <SearchBar
416→        value={query}
417→        onChange={handleQueryChange}
418→        placeholder="Search Files..."
419→        activeDescendantId={activeDescendantId}
420→        breadcrumbs={nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined}
421→        dropdown={
422→          <SearchDropdown
423→            sections={FILTER_SECTIONS}
424→            value={filterValue}
425→            onChange={handleFilterChange}
426→          />
427→        }
428→      />
429→      <div className="command-palette__body">
430→        <div className="command-palette__list-container">
431→          {totalItemCount === 0 ? (
432→            <EmptyState
433→              icon={<SearchEmptyIcon />}
434→              title="No Results"
435→              description="Try a different search term or filter"
436→            />
437→          ) : (
438→            <List
439→              itemCount={totalItemCount}
440→              onActiveIndexChange={handleActiveIndexChange}
441→              onAction={handleAction}
442→            >
443→              {(() => {
444→                let globalIndex = 0;
445→                const sections: ReactNode[] = [];
446→
447→                if (folders.length > 0) {
448→                  sections.push(
449→                    <ListSection key="folders" title="Folders">
450→                      {folders.map(entry =>
451→                        renderFileItem(entry, globalIndex++))}
452→                    </ListSection>,
453→                  );
454→                }
455→
456→                if (files.length > 0) {
457→                  sections.push(
458→                    <ListSection key="files" title="Files">
459→                      {files.map(entry => renderFileItem(entry, globalIndex++))}
460→                    </ListSection>,
461→                  );
462→                }
463→
464→                return sections;
465→              })()}
466→            </List>
467→          )}
468→        </div>
469→      </div>
470→      <ActionPanel
471→        contextLabel="File Search"
472→        actions={[
473→          {
474→            label: 'Open',
475→            shortcut: <Kbd keys={['↵']} />,
476→          },
477→          {
478→            label: 'Actions',
479→            shortcut: (
480→              <Kbd
481→                keys={[
482→                  '⌘',
483→                  'K',
484→                ]}
485→              />
486→            ),
487→            onClick: toggleActions,
488→          },
489→        ]}
490→        dropdownOpen={actionsOpen}
491→        dropdownSections={dropdownSections}
492→        onDropdownClose={closeActions}
493→      />
494→      {alertState && (
