21→const clipboard: PlatformClipboard = {
22→  async writeText(text: string) {
23→    const { writeText } = await import('@tauri-apps/plugin-clipboard-manager');
24→    await writeText(text);
25→  },
26→  async readText() {
27→    const { readText } = await import('@tauri-apps/plugin-clipboard-manager');
28→    return readText();
29→  },
30→  async onClipboardChange(handler: (event: ClipboardChangeEvent) => void) {
