57→const platformWindow: PlatformWindow = {
58→  async hide() {
59→    const { getCurrentWindow } = await import('@tauri-apps/api/window');
60→    await getCurrentWindow().hide();
61→  },
62→  async setPositionPreference(position: string) {
63→    const { invoke } = await import('@tauri-apps/api/core');
64→    await invoke('set_window_position_pref', { position });
65→  },
66→  async onFocusChanged(handler: (focused: boolean) => void) {
67→    const { getCurrentWindow } = await import('@tauri-apps/api/window');
68→    return getCurrentWindow().onFocusChanged(({ payload: focused }) => {
69→      handler(focused);
70→    });
71→  },
72→  async onTrayNavigate(handler: (target: string) => void) {
73→    const { listen } = await import('@tauri-apps/api/event');
74→    return listen<string>('tray-navigate', event => {
75→      handler(event.payload);
76→    });
77→  },
78→  async syncStoredPositionToBackend() {
79→    const stored = storageGet(SETTINGS_STORAGE_KEY, isSettingsWithPosition);
80→    if (!stored?.windowPosition) return;
81→
82→    const { invoke } = await import('@tauri-apps/api/core');
83→    await invoke('set_window_position_pref', {
84→      position: stored.windowPosition,
85→    });
86→  },
87→};
