 23→fn position_near_top(window: &tauri::WebviewWindow) {
 24→    let monitor = window
 25→        .current_monitor()
 26→        .ok()
 27→        .flatten()
 28→        .or_else(|| window.primary_monitor().ok().flatten());
 29→
 30→    if let Some(monitor) = monitor {
 31→        let monitor_size = monitor.size();
 32→        let monitor_pos = monitor.position();
 33→
 34→        if let Ok(window_size) = window.outer_size() {
 35→            let x = monitor_pos.x + (monitor_size.width as i32 - window_size.width as i32) / 2;
 36→            let y = monitor_pos.y + (monitor_size.height as i32) / 5;
 37→
 38→            if let Err(e) = window.set_position(tauri::PhysicalPosition::new(x, y)) {
 39→                eprintln!("failed to position window: {e}");
 40→            }
 41→        }
 42→    } else if let Err(e) = window.center() {
 43→        eprintln!("failed to center window: {e}");
 44→    }
 45→}
 46→
 47→fn show_and_focus(window: &tauri::WebviewWindow) {
 48→    let position_pref = window
 49→        .app_handle()
 50→        .try_state::<Mutex<WindowConfig>>()
 51→        .and_then(|state| state.lock().ok().map(|s| s.position_pref.clone()))
 52→        .unwrap_or_else(|| "top-third".to_string());
 53→
 54→    if position_pref == "center" {
 55→        if let Err(e) = window.center() {
 56→            eprintln!("failed to center window: {e}");
 57→        }
 58→    } else {
 59→        position_near_top(window);
 60→    }
 61→
 62→    if let Err(e) = window.show() {
 63→        eprintln!("failed to show window: {e}");
 64→    }
 65→    if let Err(e) = window.set_focus() {
 66→        eprintln!("failed to focus window: {e}");
 67→    }
 68→}
