 70→fn toggle_window(window: &tauri::WebviewWindow) {
 71→    let visible = window.is_visible().unwrap_or(false);
 72→    let focused = window.is_focused().unwrap_or(false);
 73→
 74→    if visible && focused {
 75→        if let Err(e) = window.hide() {
 76→            eprintln!("failed to hide window: {e}");
 77→        }
 78→    } else if visible {
 79→        show_and_focus(window);
 80→    } else {
 81→        show_and_focus(window);
 82→    }
 83→}
