 85→fn detect_content_type(content: &str) -> &'static str {
 86→    let trimmed = content.trim();
 87→
 88→    if trimmed.starts_with("http://") || trimmed.starts_with("https://") {
 89→        return "link";
 90→    }
 91→
 92→    if (trimmed.len() == 4 || trimmed.len() == 7 || trimmed.len() == 9)
 93→        && trimmed.starts_with('#')
 94→        && trimmed[1..].chars().all(|c| c.is_ascii_hexdigit())
 95→    {
 96→        return "color";
 97→    }
 98→
 99→    if trimmed.starts_with("rgb(")
100→        || trimmed.starts_with("rgba(")
101→        || trimmed.starts_with("hsl(")
102→        || trimmed.starts_with("hsla(")
103→    {
104→        return "color";
105→    }
106→
107→    "text"
108→}
