110→fn start_clipboard_monitor(app_handle: tauri::AppHandle) {
111→    use tauri_plugin_clipboard_manager::ClipboardExt;
112→
113→    std::thread::spawn(move || {
114→        let mut last_text = String::new();
115→
116→        loop {
117→            std::thread::sleep(Duration::from_millis(500));
118→
119→            let text = match app_handle.clipboard().read_text() {
120→                Ok(t) => t,
121→                Err(_) => continue,
122→            };
123→
124→            if text.is_empty() || text == last_text {
125→                continue;
126→            }
127→            last_text = text.clone();
128→
129→            let content_type = detect_content_type(&text);
130→
131→            let elapsed = std::time::SystemTime::now()
132→                .duration_since(std::time::UNIX_EPOCH)
133→                .unwrap_or_default();
134→            let timestamp_ms = elapsed.as_secs() * 1000 + elapsed.subsec_millis() as u64;
135→
136→            let payload = serde_json::json!({
137→                "content": text,
138→                "contentType": content_type,
139→                "timestamp": timestamp_ms,
140→            });
141→
142→            if let Err(e) = app_handle.emit("clipboard-changed", payload) {
143→                eprintln!("failed to emit clipboard-changed: {e}");
144→            }
145→        }
146→    });
147→}
