149→#[tauri::command]
150→fn set_window_position_pref(
151→    state: tauri::State<'_, Mutex<WindowConfig>>,
152→    position: String,
153→) -> Result<(), String> {
154→    match position.as_str() {
155→        "center" | "top-third" => {
156→            if let Ok(mut config) = state.lock() {
157→                config.position_pref = position;
158→                Ok(())
159→            } else {
160→                Err("failed to acquire config lock".to_string())
161→            }
162→        }
163→        _ => Err(format!("invalid position: {position}")),
164→    }
165→}
