167→#[cfg_attr(mobile, tauri::mobile_entry_point)]
168→pub fn run() {
169→    tauri::Builder::default()
170→        .plugin(tauri_plugin_clipboard_manager::init())
171→        .manage(Mutex::new(WindowConfig::default()))
172→        .invoke_handler(tauri::generate_handler![set_window_position_pref])
173→        .setup(|app| {
174→            #[cfg(desktop)]
175→            {
176→                let shortcut = Shortcut::new(Some(Modifiers::ALT), Code::Space);
177→                let window = app
178→                    .get_webview_window("main")
179→                    .expect("main window not found");
180→
181→                let window_for_blur = window.clone();
182→                window.on_window_event(move |event| {
183→                    if let tauri::WindowEvent::Focused(false) = event {
184→                        if let Err(e) = window_for_blur.hide() {
185→                            eprintln!("failed to hide on blur: {e}");
186→                        }
187→                    }
188→                });
189→
190→                #[cfg(target_os = "macos")]
191→                {
192→                    use window_vibrancy::{apply_vibrancy, NSVisualEffectMaterial};
193→                    if let Err(e) =
194→                        apply_vibrancy(&window, NSVisualEffectMaterial::HudWindow, None, None)
195→                    {
196→                        eprintln!("failed to apply vibrancy: {e}");
197→                    }
198→                }
199→
200→                position_near_top(&window);
201→
202→                start_clipboard_monitor(app.handle().clone());
203→
204→                let window_for_shortcut = window.clone();
205→                app.handle().plugin(
206→                    tauri_plugin_global_shortcut::Builder::new()
207→                        .with_handler(move |_app, scut, event| {
208→                            if scut == &shortcut && event.state() == ShortcutState::Pressed {
209→                                toggle_window(&window_for_shortcut);
210→                            }
211→                        })
212→                        .build(),
213→                )?;
214→
215→                app.global_shortcut().register(shortcut)?;
216→
217→                let show_item =
218→                    MenuItem::with_id(app, "show", "Show Raycast", true, None::<&str>)?;
219→                let clipboard_item =
220→                    MenuItem::with_id(app, "clipboard", "Clipboard History", true, None::<&str>)?;
221→                let snippets_item =
222→                    MenuItem::with_id(app, "snippets", "Snippets", true, None::<&str>)?;
223→                let settings_item =
224→                    MenuItem::with_id(app, "settings", "Settings", true, None::<&str>)?;
225→                let check_updates_item = MenuItem::with_id(
226→                    app,
227→                    "check-updates",
228→                    "Check for Updates",
229→                    true,
230→                    None::<&str>,
231→                )?;
232→                let about_item =
233→                    MenuItem::with_id(app, "about", "About Raycast Clone", true, None::<&str>)?;
234→                let quit_item = MenuItem::with_id(app, "quit", "Quit", true, None::<&str>)?;
235→
236→                let menu = Menu::with_items(
237→                    app,
238→                    &[
239→                        &show_item,
240→                        &PredefinedMenuItem::separator(app)?,
241→                        &clipboard_item,
242→                        &snippets_item,
243→                        &settings_item,
244→                        &PredefinedMenuItem::separator(app)?,
245→                        &check_updates_item,
246→                        &about_item,
247→                        &quit_item,
248→                    ],
249→                )?;
250→
251→                let window_for_menu = window.clone();
252→                let window_for_tray = window.clone();
253→
254→                TrayIconBuilder::new()
255→                    .icon(tauri::image::Image::from_bytes(include_bytes!(
256→                        "../icons/tray-icon@2x.png"
257→                    ))?)
258→                    .icon_as_template(true)
259→                    .tooltip("Raycast Clone")
260→                    .menu(&menu)
261→                    .show_menu_on_left_click(false)
262→                    .on_menu_event(move |app, event| match event.id().as_ref() {
263→                        "show" => {
264→                            show_and_focus(&window_for_menu);
265→                        }
266→                        "clipboard" | "snippets" | "settings" | "about" | "check-updates" => {
267→                            show_and_focus(&window_for_menu);
268→                            if let Err(e) =
269→                                app.emit("tray-navigate", event.id().as_ref().to_string())
270→                            {
271→                                eprintln!("failed to emit tray-navigate: {e}");
272→                            }
273→                        }
274→                        "quit" => {
275→                            app.exit(0);
276→                        }
277→                        _ => {}
278→                    })
279→                    .on_tray_icon_event(move |_tray, event| {
280→                        if let TrayIconEvent::Click {
281→                            button: MouseButton::Left,
282→                            button_state: MouseButtonState::Up,
283→                            ..
284→                        } = event
285→                        {
286→                            toggle_window(&window_for_tray);
287→                        }
288→                    })
289→                    .build(app)?;
290→            }
291→
292→            Ok(())
293→        })
294→        .run(tauri::generate_context!())
295→        .expect("error while running tauri application");
296→}
